//! P4d SCENE-LEVEL RELATIONAL INTELLIGENCE — a per-tick read of the room's STRUCTURE that stays
//! useful when every object's rigid-body regime ABSTAINS.
//!
//! `object_intel` certifies a single body's dynamical regime by which conservation laws hold;
//! `interaction` certifies a brief two-body COLLISION by total-momentum conservation. Both go silent
//! on the common real-footage case this module addresses: a hand grabbing a controller. The grab is
//! deformable + muscle-actuated, so no rigid regime certifies (it reads `non_rigid_actuated`), and it
//! is NOT a clean momentum-conserving two-body event (the muscle is an unobserved third party
//! injecting momentum), so the collision certificate correctly DECLINES/abstains. The scene is still
//! legible, though — from PROXIMITY and RELATIVE MOTION alone — and that legible structure is what
//! this layer reports.
//!
//! WHAT IT REPORTS (per tick, robust to regime-abstain):
//!  * how many objects are tracked, and how many are MOVING.
//!  * RELATIONS between pairs:
//!      - GRAB / MANIPULATION: SUSTAINED contact (proximity held over many frames, distinct from a
//!        collision's brief touch) WHERE the two bodies CO-MOVE (their velocity vectors correlate —
//!        the hand carries the controller). This is reported as a DETECTED RELATION, explicitly NOT a
//!        conservation certificate: a grab is actuated, the muscle is an unobserved force, so there is
//!        no two-body momentum-conservation claim. The honest gate is sustained-contact + co-motion.
//!
//! HONEST BOUNDS (load-bearing):
//!  * A grab is a DETECTED relation, not a certified law. We assert it only on sustained contact AND
//!    correlated co-motion, and we say so — we never dress it up as momentum conservation.
//!  * Everything is RELATIVE-scale and IN-PLANE (the same monocular limits as `object_intel`).
//!  * This does NOT make a deformable hand a rigid body. The value is (1) the informative abstain on
//!    each object (`object_intel::AbstainReason`), and (2) this relational read that works precisely
//!    when the rigid regimes can't.
//!  * If the two bodies do not both track cleanly as SEPARATE objects through the contact (the hand
//!    occludes/merges the controller into one silhouette), there is no pair to relate — we report a
//!    single object with its informative abstain and DO NOT invent a grab. The grab needs two tracks.

use crate::interaction::MomentumSample;
use crate::object_intel::AbstainReason;
use std::collections::HashMap;

/// The kind of detected relation between two tracked objects.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RelationKind {
    /// Sustained contact + correlated co-motion: one body carries/manipulates the other (a grab).
    /// A DETECTED relation, NOT a momentum-conservation certificate (the actuating muscle is an
    /// unobserved third party).
    Grab,
}

impl RelationKind {
    pub fn as_str(self) -> &'static str {
        match self {
            RelationKind::Grab => "grab/manipulation",
        }
    }
}

/// A detected scene-level relation between two tracked objects this tick.
#[derive(Debug, Clone)]
pub struct Relation {
    pub a_id: u64,
    pub b_id: u64,
    pub kind: RelationKind,
    /// Consecutive ticks the pair has been in contact (the sustained-contact evidence).
    pub contact_frames: u32,
    /// Co-motion correlation in [-1, 1]: cosine similarity of the two velocity vectors, averaged
    /// over the contact window. Near +1 => moving together (carried). Gated above `comotion_min`.
    pub comotion: f32,
    /// Mean centroid separation over the contact window, in units of (size_a + size_b). < ~1 => the
    /// silhouettes overlap/touch.
    pub rel_separation: f32,
}

impl Relation {
    /// One-line read, honest about what it is (detected, not certified).
    pub fn summary(&self) -> String {
        match self.kind {
            RelationKind::Grab => format!(
                "#{} and #{} in SUSTAINED contact ({} frames) with correlated co-motion (corr {:+.2}) — a manipulation/grab (DETECTED relation, not a momentum-conservation certificate: the actuating force is unobserved)",
                self.a_id, self.b_id, self.contact_frames, self.comotion
            ),
        }
    }
}

/// Per-tick scene-level structural read. Robust to every object's regime abstaining.
#[derive(Debug, Clone, Default)]
pub struct SceneIntelTick {
    pub round: u64,
    pub pts: f64,
    /// Total tracked (admitted) objects this tick.
    pub n_objects: usize,
    /// How many are MOVING (speed >= moving_speed).
    pub n_moving: usize,
    /// Objects whose informative-abstain reason is `non_rigid_actuated` (deforming/actuated bodies).
    pub non_rigid_ids: Vec<u64>,
    /// Detected relations (grabs) this tick.
    pub relations: Vec<Relation>,
}

impl SceneIntelTick {
    /// One-line headline of the scene structure, e.g.
    /// "3 tracked objects (2 moving); #4 non-rigid/actuated; #4 and #7 in sustained contact with
    ///  correlated motion (a manipulation/grab)".
    pub fn headline(&self) -> String {
        let mut s = format!(
            "{} tracked object{} ({} moving)",
            self.n_objects,
            if self.n_objects == 1 { "" } else { "s" },
            self.n_moving
        );
        if !self.non_rigid_ids.is_empty() {
            let ids: Vec<String> = self.non_rigid_ids.iter().map(|i| format!("#{i}")).collect();
            s.push_str(&format!("; {} non-rigid/actuated", ids.join(", ")));
        }
        for r in &self.relations {
            s.push_str(&format!(
                "; #{} and #{} in sustained contact with correlated motion (a {})",
                r.a_id, r.b_id, r.kind.as_str()
            ));
        }
        if self.relations.is_empty() && self.n_objects >= 2 {
            s.push_str("; no sustained-contact relation (no grab)");
        }
        s
    }
}

/// Tunables for the scene-level relational read. Defaults favour reporting a relation only on
/// genuinely sustained contact + clear co-motion (no spurious grabs from a brief brush-by).
#[derive(Debug, Clone)]
pub struct SceneIntelConfig {
    /// Speed (normalised u/s) at/above which an object counts as moving.
    pub moving_speed: f32,
    /// Two objects are "in contact" when their centroid separation is below this multiple of the sum
    /// of their characteristic sizes. ~1.2 => silhouettes touch/overlap.
    pub contact_factor: f32,
    /// Minimum CONSECUTIVE contact ticks to call the contact SUSTAINED (a grab, not a collision's
    /// brief touch). This is the temporal separator from `interaction`'s instantaneous collision.
    pub sustained_frames: u32,
    /// Minimum co-motion correlation (cosine of the two velocity vectors, averaged over the window)
    /// to call the pair co-moving (carried). Below this they merely happen to be near each other.
    pub comotion_min: f32,
    /// Minimum speed of AT LEAST ONE of the pair to test co-motion (two near-still objects have no
    /// meaningful velocity direction — their correlation is noise).
    pub comotion_speed_min: f32,
    /// Window depth (ticks) kept per pair for the co-motion average.
    pub window: usize,
}

impl Default for SceneIntelConfig {
    fn default() -> Self {
        SceneIntelConfig {
            moving_speed: 0.03,
            contact_factor: 1.2,
            sustained_frames: 6,
            comotion_min: 0.5,
            comotion_speed_min: 0.02,
            window: 10,
        }
    }
}

/// Rolling per-pair contact + co-motion state (cross-tick memory the per-tick scene lacks).
#[derive(Debug, Clone, Default)]
struct PairState {
    /// Consecutive ticks the pair has been in contact (resets to 0 when they separate).
    contact_streak: u32,
    /// Last `window` co-motion correlations and separations while in contact (most recent last).
    comotion_hist: std::collections::VecDeque<f32>,
    sep_hist: std::collections::VecDeque<f32>,
    /// Round last updated, to GC stale pairs.
    last_round: u64,
}

/// The scene-level relational detector. Persists across ticks (like `InteractionDetector`).
#[derive(Debug, Clone)]
pub struct SceneIntel {
    cfg: SceneIntelConfig,
    pairs: HashMap<(u64, u64), PairState>,
}

impl SceneIntel {
    pub fn new() -> Self {
        Self::with_config(SceneIntelConfig::default())
    }

    pub fn with_config(cfg: SceneIntelConfig) -> Self {
        SceneIntel { cfg, pairs: HashMap::new() }
    }

    pub fn config(&self) -> &SceneIntelConfig {
        &self.cfg
    }

    /// Observe this tick's per-object samples (the same `MomentumSample` the interaction detector
    /// consumes) plus their abstain reasons, update the rolling per-pair state, and return the
    /// per-tick scene structural read. `reasons` maps object id -> its informative-abstain reason.
    pub fn observe(
        &mut self,
        round: u64,
        pts: f64,
        samples: &[MomentumSample],
        reasons: &HashMap<u64, AbstainReason>,
    ) -> SceneIntelTick {
        // Per-object velocity (from p/mass) and moving flag.
        let vel = |s: &MomentumSample| -> (f32, f32) {
            let m = s.mass.max(1e-9);
            (s.px / m, s.py / m)
        };
        let speed = |s: &MomentumSample| -> f32 {
            let (vx, vy) = vel(s);
            (vx * vx + vy * vy).sqrt()
        };

        let n_objects = samples.len();
        let n_moving = samples.iter().filter(|s| speed(s) >= self.cfg.moving_speed).count();
        let non_rigid_ids: Vec<u64> = samples
            .iter()
            .filter(|s| reasons.get(&s.id).copied() == Some(AbstainReason::NonRigidActuated))
            .map(|s| s.id)
            .collect();

        // Update every co-present pair's contact + co-motion state and emit any sustained-contact
        // co-moving relation.
        let mut relations = Vec::new();
        let seen_pairs: std::collections::HashSet<(u64, u64)> = {
            let mut set = std::collections::HashSet::new();
            for i in 0..samples.len() {
                for j in (i + 1)..samples.len() {
                    let (a, b) = (&samples[i], &samples[j]);
                    let key = if a.id < b.id { (a.id, b.id) } else { (b.id, a.id) };
                    set.insert(key);

                    let dx = a.x - b.x;
                    let dy = a.y - b.y;
                    let dist = (dx * dx + dy * dy).sqrt();
                    let size_sum = (a.size + b.size).max(1e-6);
                    let rel_sep = dist / size_sum;
                    let in_contact = rel_sep <= self.cfg.contact_factor;

                    let st = self.pairs.entry(key).or_default();
                    st.last_round = round;
                    if in_contact {
                        st.contact_streak = st.contact_streak.saturating_add(1);
                        // Co-motion: cosine similarity of the two velocity vectors (when at least one
                        // is moving enough to have a meaningful direction).
                        let (avx, avy) = vel(a);
                        let (bvx, bvy) = vel(b);
                        let sa = (avx * avx + avy * avy).sqrt();
                        let sb = (bvx * bvx + bvy * bvy).sqrt();
                        if sa.max(sb) >= self.cfg.comotion_speed_min {
                            let denom = (sa * sb).max(1e-9);
                            let cos = ((avx * bvx + avy * bvy) / denom).clamp(-1.0, 1.0);
                            st.comotion_hist.push_back(cos);
                            st.sep_hist.push_back(rel_sep);
                            while st.comotion_hist.len() > self.cfg.window {
                                st.comotion_hist.pop_front();
                            }
                            while st.sep_hist.len() > self.cfg.window {
                                st.sep_hist.pop_front();
                            }
                        }
                    } else {
                        // Separated: the contact (and thus any grab) is over.
                        st.contact_streak = 0;
                        st.comotion_hist.clear();
                        st.sep_hist.clear();
                    }

                    // RELATION GATE: sustained contact AND clear co-motion over the window.
                    if st.contact_streak >= self.cfg.sustained_frames && !st.comotion_hist.is_empty() {
                        let mean_corr =
                            st.comotion_hist.iter().sum::<f32>() / st.comotion_hist.len() as f32;
                        let mean_sep = if st.sep_hist.is_empty() {
                            rel_sep
                        } else {
                            st.sep_hist.iter().sum::<f32>() / st.sep_hist.len() as f32
                        };
                        if mean_corr >= self.cfg.comotion_min {
                            relations.push(Relation {
                                a_id: key.0,
                                b_id: key.1,
                                kind: RelationKind::Grab,
                                contact_frames: st.contact_streak,
                                comotion: mean_corr,
                                rel_separation: mean_sep,
                            });
                        }
                    }
                }
            }
            set
        };

        // GC pairs not seen this tick (a track ended / pair split apart for good).
        let keep_round = round;
        self.pairs
            .retain(|k, st| seen_pairs.contains(k) || keep_round.saturating_sub(st.last_round) <= 2);

        SceneIntelTick { round, pts, n_objects, n_moving, non_rigid_ids, relations }
    }
}

impl Default for SceneIntel {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::object_intel::Regime;

    fn sample(id: u64, x: f32, y: f32, vx: f32, vy: f32, regime: Regime) -> MomentumSample {
        let m = 1.0f32;
        MomentumSample {
            id,
            round: 0,
            pts: 0.0,
            mass: m,
            x,
            y,
            size: 0.05,
            px: m * vx,
            py: m * vy,
            ke: 0.5 * m * (vx * vx + vy * vy),
            regime,
            confidence: 1.0,
            material: crate::object_intel::MaterialKind::Unknown,
            grounded: false,
        }
    }

    /// A hand (#1) carrying a controller (#2): the two stay in contact and co-move (same velocity)
    /// for many frames => a GRAB relation is detected (sustained + correlated), NOT a collision.
    #[test]
    fn sustained_comoving_contact_detects_grab() {
        let mut si = SceneIntel::new();
        let reasons: HashMap<u64, AbstainReason> = HashMap::new();
        let mut last = SceneIntelTick::default();
        // Both drift together at the same velocity, touching (separation ~ 1 size-sum).
        let (mut x1, mut x2) = (0.30f32, 0.38f32);
        for r in 0..20u64 {
            let v = 0.04f32;
            x1 += v;
            x2 += v;
            let batch = vec![
                sample(1, x1, 0.5, v, 0.0, Regime::Abstain),
                sample(2, x2, 0.5, v, 0.0, Regime::Abstain),
            ];
            last = si.observe(r, r as f64 / 30.0, &batch, &reasons);
        }
        assert_eq!(last.relations.len(), 1, "one grab relation: {:?}", last.relations);
        let rel = &last.relations[0];
        assert_eq!(rel.kind, RelationKind::Grab);
        assert!(rel.contact_frames >= 6, "sustained: {}", rel.contact_frames);
        assert!(rel.comotion > 0.9, "co-moving: corr {}", rel.comotion);
        assert_eq!(last.n_objects, 2);
        assert_eq!(last.n_moving, 2);
    }

    /// A brief collision (two objects touch for ONE tick then separate moving APART) is NOT a grab:
    /// the contact is not sustained and the co-motion is anti-correlated. The scene-intel layer must
    /// stay silent so the grab read does not duplicate / mislabel a collision.
    #[test]
    fn brief_collision_is_not_a_grab() {
        let mut si = SceneIntel::new();
        let reasons: HashMap<u64, AbstainReason> = HashMap::new();
        let mut any_grab = false;
        // A approaches from the left, B from the right; they touch at the middle tick then recede.
        for r in 0..20u64 {
            let t = r as f32;
            let ax = 0.20 + 0.03 * t; // moving right
            let bx = 0.80 - 0.03 * t; // moving left
            let batch = vec![
                sample(1, ax, 0.5, 0.03, 0.0, Regime::Forced),
                sample(2, bx, 0.5, -0.03, 0.0, Regime::Forced),
            ];
            let tick = si.observe(r, r as f64 / 30.0, &batch, &reasons);
            if !tick.relations.is_empty() {
                any_grab = true;
            }
        }
        assert!(!any_grab, "a brief crossing collision must NOT read as a sustained grab");
    }

    /// Two objects near each other but moving in OPPOSITE directions (not carried) — sustained
    /// contact but anti-correlated motion => no grab (co-motion gate rejects it).
    #[test]
    fn sustained_contact_without_comotion_is_not_a_grab() {
        let mut si = SceneIntel::new();
        let reasons: HashMap<u64, AbstainReason> = HashMap::new();
        let mut last = SceneIntelTick::default();
        // Held at a fixed touching separation but velocities point opposite ways (shear, not carry).
        for r in 0..20u64 {
            let phase = (r as f32) * 0.5;
            let v = 0.05f32;
            let batch = vec![
                sample(1, 0.45, 0.5 + 0.001 * phase, v, 0.0, Regime::Abstain),
                sample(2, 0.52, 0.5 - 0.001 * phase, -v, 0.0, Regime::Abstain),
            ];
            last = si.observe(r, r as f64 / 30.0, &batch, &reasons);
        }
        assert!(last.relations.is_empty(), "anti-correlated motion => no grab: {:?}", last.relations);
    }

    /// A single tracked object cannot form a relation — the headline reports the object and any
    /// non-rigid annotation, never a grab.
    #[test]
    fn single_object_no_relation() {
        let mut si = SceneIntel::new();
        let mut reasons: HashMap<u64, AbstainReason> = HashMap::new();
        reasons.insert(1, AbstainReason::NonRigidActuated);
        let tick = si.observe(0, 0.0, &[sample(1, 0.5, 0.5, 0.06, 0.0, Regime::Abstain)], &reasons);
        assert!(tick.relations.is_empty());
        assert_eq!(tick.non_rigid_ids, vec![1]);
        assert!(tick.headline().contains("non-rigid/actuated"), "{}", tick.headline());
    }
}
